export function applyDiscount(order: Order, promo: PromoCode): Order {
  if (!promo.active) return order;
  const raw = order.subtotal * promo.percent;
  const capped = Math.min(raw, 25);
  const newSubtotal = order.subtotal - capped;
  return {
    ...order,
    discount: capped,
    subtotal: newSubtotal,
    total: newSubtotal + order.tax,
  };
}

after.bodyText:
export function applyDiscount(order: Order, promo: PromoCode): Order {
  if (!promo.active) return order;
  const raw = order.subtotal * promo.percent;
  const cap = order.customer.tier === 'vip' ? 100 : 25;
  const capped = Math.min(raw, cap);
  const newSubtotal = order.subtotal - capped;
  return {
    ...order,
    discount: capped,
    subtotal: newSubtotal,
    total: newSubtotal + order.tax,
  };
}
